{"code": "import json

# Load the paper documents
paper_docs_file = locals()['var_functions.query_db:20']
with open(paper_docs_file, 'r') as f:
    paper_docs = json.load(f)

# Load citations
citations_file = locals()['var_functions.query_db:8']
with open(citations_file, 'r') as f:
    citations = json.load(f)

# Create comprehensive paper to text mapping
paper_texts = {}
for doc in paper_docs:
    filename = doc['filename']
    title = filename.replace('.txt', '')
    paper_texts[title] = doc['text']

# Define domain keywords for food
food_keywords = ['food', 'eating', 'nutrition', 'diet', 'meal', 'calorie', 'dietary', 'weight']

# Check which papers contain food-related content
food_papers = []
for title, text in paper_texts.items():
    text_lower = text.lower()
    # Count mentions of each food keyword
    keyword_hits = {}
    for keyword in food_keywords:
        count = text_lower.count(keyword)
        if count > 0:
            keyword_hits[keyword] = count

    if keyword_hits:
        food_papers.append({
            'title': title,
            'keyword_hits': keyword_hits,
            'total_mentions': sum(keyword_hits.values())
        })

# Sort by total mentions
food_papers.sort(key=lambda x: x['total_mentions'], reverse=True)

print('__RESULT__:')
print(json.dumps({
    'food_papers': food_papers,
    'num_food_papers': len(food_papers)
}, indent=2))"}

